[[0, 31, 'm\'\nGREEN=\'033[0;32m\'\nYELLOW=\'033[1;33m\'\nNC=\'033[0m\'\n\nscriptDir="$(cd "$(dirname", \'}', {'$repoRoot="$(cd "$scriptDir/.." && pwd)"\nenvPath="$repoRoot/.env"\n\n# Parse arguments\nDatabase=""\nServerName=""\nwhile [[ $# -gt 0 ]]; do\n    case $1 in\n        -Database)\n            Database="$2"\n            shift 2\n            ;;\n        -ServerName)\n            ServerName="$2"\n            shift 2\n            ;;\n        *)\n            echo "Unknown parameter: $1"\n            exit 1\n            ;;\n    esac\ndone\n\nif [ -z "$Database" ]; then\n    echo "Usage: $0 -Database <database_name> [-ServerName <server_name>]"\n    exit 1\nfi\n\nif [ ! -f "$envPath" ]; then\n    echo -e': {"$YELLOW}[SOVA]${NC} Skipped: .env not found at project root'\n    exit 0\nfi\n\n# Load .env file\ndeclare -A envVars\nwhile IFS='=": 'ead -r key value || [ -n', 'key': 'do\n    [[ -z', '$key': 'continue\n    # Remove surrounding quotes if present\n    value=', 'envVars["$key': '$value"\ndone < "$envPath"\n\nprovider=', 'envVars["VITE_AI_PROVIDER': 'grok'}, 'nopenai="${envVars["OPENAI_API_KEY': ''}, '\\ngemini="${envVars["GEMINI_API_KEY'], {'envVars["GROK_API_KEY': ''}, ['z "$openai'], ['z "$gemini'], ['z "$grok'], {"$YELLOW}[SOVA]${NC} Skipped: no OPENAI_API_KEY, GEMINI_API_KEY, or GROK_API_KEY in .env'\n    exit 0\nfi\n\necho -e": {'$YELLOW}[SOVA]${NC} Seeding ai_http_config from .env (provider: $provider)...': 'n\n# Build command\ncmd=(spacetime call --no-config)\nif [ -n', '$ServerName")\nfi\ncmd+=("$Database" configure_sova "$provider" "$openai" "$gemini" "$grok")': {'$ServerName" ]; then\n    spacetime sql --no-config --server "$ServerName" "$Database" "SELECT id, active_provider FROM ai_http_config"\nelse\n    spacetime sql --no-config "$Database" "SELECT id, active_provider FROM ai_http_config': "nfi\n\necho -e': {'$GREEN"}, "verified'": ''}}]